const text = $input.first().json.body?.text || $input.first().json.text || '';

// 简单的中文 NLP 解析（模拟 AI）
const tasks = [];
const lines = text.split(/[，,；;。！!\n]+/).filter(l => l.trim());

for (const line of lines) {
  const title = line.trim();
  if (!title) continue;

  // 检测优先级
  let priority = 'MEDIUM';
  if (/紧急|urgent|加急/i.test(title)) priority = 'URGENT';
  else if (/重要|high/i.test(title)) priority = 'HIGH';
  else if (/低优先|low/i.test(title)) priority = 'LOW';

  // 检测工时
  let estimatedHours = 4;
  const hourMatch = title.match(/(\d+)\s*[小时天h]/);
  if (hourMatch) estimatedHours = parseInt(hourMatch[1]);

  tasks.push({
    title: title.replace(/\d+\s*[小时天h]/g, '').replace(/紧急|重要|低优先/g, '').trim(),
    estimatedHours,
    priority,
    description: line,
  });
}

return tasks.map(t => ({ json: t }));
